#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t A,Y,X; scanf("%" PRId64 " %" PRId64 " %" PRId64, &A, &Y, &X);
        int64_t ans = (A < Y) ? (1 + A*X) : (Y*X);
        printf("%" PRId64 "\n", ans);
    }
    return 0;
}

