import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); Y = int(next(it)); X = int(next(it))
        if A < Y:
            out.append(str(1 + A * X))
        else:
            out.append(str(Y * X))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

